using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ConfigMcpServer", Version = "1.0.0" };
    options.ServerInstructions = "Provides configuration data and greeting tools.";
})
.WithHttpTransport()
.WithToolsFromAssembly()
.WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();                          // MCP endpoint at /mcp
app.MapGet("/health", () => "ok");     // health check for orchestrators

app.Run();

