using System.Text.Json;
using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["featureFlags"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/{section}",
        Name = "Config Section",
        MimeType = "application/json"),
     Description("Returns a specific configuration section by name.")]
    public static string GetConfigSection(
        [Description("Configuration section name (e.g. 'featureFlags')")] string section)
    {
        if (AppConfig.TryGetValue(section, out var value))
            return JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true });

        return JsonSerializer.Serialize(new { error = $"Section '{section}' not found" });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a personalized greeting message.")]
    public static string Greet(
        [Description("Name of the person to greet")] string name) =>
        $"Hello, {name}! Welcome to the ConfigMcpServer.";
}

